function solve(n: number, edges: number[][], label: string): number {
    const adj = new Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 1;

    function isPalindrome(s: string): boolean {
        let left = 0, right = s.length - 1;
        while (left < right) {
            if (s[left] !== s[right]) return false;
            left++;
            right--;
        }
        return true;
    }

    function dfs(node: number, visited: number, currentStr: string): void {
        if (isPalindrome(currentStr)) {
            maxLen = Math.max(maxLen, currentStr.length);
        }

        for (const neighbor of adj[node]) {
            if ((visited & (1 << neighbor)) === 0) {
                const newVisited = visited | (1 << neighbor);
                const newStr = currentStr + label[neighbor];
                dfs(neighbor, newVisited, newStr);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        dfs(i, 1 << i, label[i]);
    }

    return maxLen;
}
